var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"......도망쳤나?","JPN":"……退散か？","ENG":"Did she run?","TWN":"……逃跑了嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"다른 녀석들도 더 이상 부활하지 않는 걸 보니 아무래도 불멸체 코어를 파괴하는 데 성공했나 보군.","JPN":"他の奴らも復活しないってことは、どうやら不滅体コアの破壊に成功したようだな。","ENG":"The rest of the Replacers are not regenerating anymore. It seems they managed to destroy the Immortal System Core.","TWN":"其他人也不再復活了，看來成功破壞不滅者核心了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"남은 건...... 신입 애송이가 직접 극복해야 할 일이겠지.","JPN":"後は……新人が自分で乗り越えなきゃな。","ENG":"And what's to come will rest upon the hands of the rookie herself.","TWN":"剩下的……就是新人小鬼得直接克服的事情了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그렇지 않으면...... 이번에도 미래는 없을 테니까.","JPN":"そうしなければ……今回も未来はないだろう。","ENG":"If she fails, there will be no future this time around either.","TWN":"不然的話……這次也不會有未來。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"못 보던 사이에 성인군자가 다 되셨군. 힐데.","JPN":"見ない間に、聖人にでもなったつもりか？　ヒルデ。","ENG":"Wow, you almost sound like a saint, Hilde.","TWN":"好久不見的這段時間，妳也變成了聖人君子了呢，希爾德。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"다들 스승이라고 떠받들어 줘서 그런가...... 그 짓거리도 꽤 어울리는걸?","JPN":"みんなが師匠、師匠とあがめてくれるからか？　偉そうなマネも、ずいぶん馴染んできたな。","ENG":"Maybe it's because everyone calls you Master. I must say, what you're doing suits you.","TWN":"是因為大家都遵奉妳為師父……所以這惡劣玩笑才那麼合適嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"물론 네 본성을 아무도 모를 때의 이야기지만.","JPN":"もちろん、其方の本性を知らないからだろうが。","ENG":"I just hope that no one finds out about your true colors.","TWN":"當然，那是在沒有人知道妳的本性的時候。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"언제쯤 나타날지 궁금했는데 이제야 무거운 엉덩이를 뗐나 보군.","JPN":"いつ現れるか気になってたが、やっと重い腰を上げたのか。","ENG":"So you finally decided to move your butt. I was wondering when that'd be.","TWN":"因為不知道什麼時候才能出現，所以妳的大屁股已經坐不住了嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"아니? 난 지금도 앉아 있는데?","JPN":"いや？　今も変わらず座ってるのじゃ。","ENG":"Oh, my butt hasn't been lifted at all, Hilde.","TWN":"沒有啊？我現在還坐著啊？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"내 엉덩이를 들어올리고 싶으면 좀 더 분발해야 할 거야, 힐데.","JPN":"妾の腰を上げさせたいなら、もう少し頑張りが必要であろう、ヒルデ。","ENG":"You're going to have to work much harder to make me lift my butt.","TWN":"想要抬起我的屁股，妳還得再努力一點啊，希爾德。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"사실 조금 전부터 보고 있었는데...... 그 반편이를 상대로 헉헉대는 네 꼴사나운 모습이 아주 재미있었거든.","JPN":"さっきから見ておったが……あの間抜けにさえ苦戦するお前のみっともない姿が、実に見ものじゃった。","ENG":"I've been watching you for quite a while, actually. It was hilarious that you were trying so hard to get yourself together against that puny thing.","TWN":"我剛剛就在看……妳在對付那個半吊子時，氣喘吁吁的醜陋模樣非常有趣呢。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"좋아하던 스타가 영락한 모습을 보는 것 같아서 마음이 아파.","JPN":"昔好きだったスターが地に落ちたところを見ているようで、心が痛むのじゃ。","ENG":"My heart breaks for you, likes a fan does for a star that lost all of her past glamour.","TWN":"就好像是看到曾經喜歡的明星落魄潦倒的樣子，真令人心痛。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"네가 전력을 개방했다면 불멸체 코어 같은 장난감이 재생 같은 귀여운 짓을 하진 못했을 텐데......","JPN":"其方が全力を出していれば、不滅体コアごときオモチャが、再生みたいなイタズラはできなかったはず……","ENG":"That toy named Immortal System Core wouldn't have pulled off those cute stunts like regeneration if you had unleashed your power to the fullest.","TWN":"妳要是使出全力的話，像不滅者核心那種玩具，應該也沒辦法做再生這種這麼可愛的事情吧……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"단말을 넘어 본체까지 인과 연결의 타격이 갔을 테니까. 그렇지 않아?","JPN":"端末を越え、本体まで打撃があったはずじゃ。そうじゃろう？","ENG":"The damage to the terminal would have been so great that it would have destroyed the core connected to it. Don't you agree?","TWN":"那應該能越過終端，連本體都受到因果上的打擊吧。不是嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"......누구 좋으라고 내가 그런 짓을 하지?","JPN":"……誰のために、私がわざわざそんなことを？","ENG":"And who would I be doing that for?","TWN":"我為什麼要對別人言聽計從，去做這件事？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"하하, 하긴 그렇지.","JPN":"ハハ、まあ、そうじゃろうな。","ENG":"Hah hah, you got me.","TWN":"哈哈，說得也是。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"네가 전력을 개방할 정도의 클리포트 인자가 활성화 됐으면 벌써 클리포트의 마왕들이 모두 깨어났을 테니까.","JPN":"其方が全力を出すほどのクリフォト・ファクターが活性化していたら、\\nクリフォトの魔王ら全員がとっくに目覚めていただろう。","ENG":"If you activated enough Qliphoth Factors to release your full power, you would have awakened all the Demon Lord of Qliphoth.","TWN":"要是妳使出全力，使得逆卡巴拉因子活性化的話，逆卡巴拉魔王們會全部醒過來吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"......지금 깨어난 건 누구지?","JPN":"……今、目覚めているのは誰だ？","ENG":"How many of you are awake?","TWN":"……現在醒過來的有誰？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};